14	var newCmd = &cobra.Command{
15		Use:     "new <name>",
16		Aliases: []string{"create"},
17		GroupID: groupWorkflow,
18		Short:   "Create a new worktree with a feature branch",
19		Long: `Create a new worktree with a feature branch based on your configured base branch.
20	
21	By default, creates a branch named "<prefix>/<name>" from the base branch
22	(configurable in .wt.toml, defaults to "main").
23	
24	Use --from to create a worktree from an existing branch or PR number.`,
25		Example: `  wt new sidebar-card              Create <user>/sidebar-card from base branch
26	  wt new --from feature/old        Create worktree from existing branch
27	  wt new fix --from origin/hotfix  Create worktree with custom name from remote
28	  wt new --from #123               Create worktree from PR #123's branch
29	  wt new feature --init            Create + auto-initialize`,
30		Args: cobra.MaximumNArgs(1),
31		RunE: runNew,
32	}
