34	var (
35		newFromBranch string
36		newDoInit     bool
37	)
38	
39	func init() {
40		newCmd.Flags().StringVarP(&newFromBranch, "from", "f", "", "base on an existing branch or PR number")
41		newCmd.Flags().BoolVarP(&newDoInit, "init", "i", false, "run 'wt init' after creating")
42		rootCmd.AddCommand(newCmd)
43	}
44	
45	func runNew(cmd *cobra.Command, args []string) error {
46		ctx, err := newContext()
47		if err != nil {
48			return err
49		}
50	
51		var name string
52		if len(args) > 0 {
53			name = args[0]
54		}
55	
56		// --from mode: create worktree from existing branch
57		if newFromBranch != "" {
58			return newFromExisting(ctx, name, newFromBranch)
59		}
60	
61		if name == "" {
62			return fmt.Errorf("name is required\n\nUsage: wt new <name>\n       wt new --from <branch>")
63		}
64	
65		return newFromBase(ctx, name)
66	}
