68	func newFromExisting(ctx *cmdContext, name, fromBranch string) error {
69		// Check if --from is a PR number (e.g., "#123" or "123")
70		if prNumber, ok := parsePRNumber(fromBranch); ok {
71			return newFromPR(ctx, name, prNumber)
72		}
73	
74		// Fetch to get latest refs (needed for ResolveBranch to find remote branches)
75		spin := ui.NewSpinner("Fetching latest refs")
76		if err := git.FetchAll(ctx.Config.Remote); err != nil {
77			spin.Stop()
78			ui.Warn("Fetch failed: %v", err)
79		} else {
80			spin.Stop()
81		}
82	
83		ref, isRemote, err := git.ResolveBranch(fromBranch, ctx.Config.Remote)
84		if err != nil {
85			return err
86		}
87	
88		// Derive name from branch if not provided
89		if name == "" {
90			name = nameFromBranch(ref, ctx.Config.Remote)
91		}
92	
93		if isRemote {
94			return createWorktreeFromRemote(ctx, name, ref, newDoInit)
95		}
96	
97		// Local branch path
98		wtPath := ctx.worktreePath(name)
99	
100		if isDir(wtPath) {
101			return fmt.Errorf("worktree already exists: %s\n   Use wt switch %s to switch to it", wtPath, name)
102		}
103	
104		fmt.Println("Creating worktree from existing branch...")
105		fmt.Printf("  Directory: %s\n", wtPath)
106		fmt.Printf("  Branch: %s\n", ref)
107		fmt.Println()
108	
109		if err := git.AddWorktreeFromExisting(wtPath, ref); err != nil {
110			return fmt.Errorf("failed to create worktree: %w", err)
111		}
112	
113		fmt.Println()
114		ui.Success("Created worktree")
115		fmt.Println()
116	
117		if newDoInit {
118			return runInitIn(wtPath, ctx)
119		}
120		printSwitchHint(name)
121		return nil
122	}
