124	// parsePRNumber checks if s looks like a PR number ("#123" or "123")
125	// and returns the parsed number if so.
126	func parsePRNumber(s string) (int, bool) {
127		s = strings.TrimPrefix(s, "#")
128		n, err := strconv.Atoi(s)
129		if err != nil || n <= 0 {
130			return 0, false
131		}
132		return n, true
133	}
134	
135	func newFromPR(ctx *cmdContext, name string, number int) error {
136		if !github.IsAvailable() {
137			return fmt.Errorf("gh CLI is required to resolve PR numbers (brew install gh)")
138		}
139	
140		spin := ui.NewSpinner(fmt.Sprintf("Fetching PR #%d", number))
141		pr, err := github.GetPRByNumber(number)
142		spin.Stop()
143		if err != nil {
144			return fmt.Errorf("failed to fetch PR #%d: %w", number, err)
145		}
146	
147		fmt.Printf("PR #%d: %s\n", pr.Number, pr.Title)
148		fmt.Println()
149	
150		if name == "" {
151			name = nameFromBranch(pr.HeadRefName, ctx.Config.Remote)
152		}
153	
154		return createWorktreeFromRemote(ctx, name, pr.HeadRefName, newDoInit)
155	}
156	
157	// nameFromBranch derives a short worktree name from a branch ref.
158	// Takes the last segment after "/" and strips the remote prefix if present.
159	//
160	//	"origin/user/fix-login" → "fix-login"
161	//	"user/fix-login"        → "fix-login"
162	//	"fix-login"             → "fix-login"
163	func nameFromBranch(ref, remote string) string {
164		parts := strings.Split(ref, "/")
165		name := parts[len(parts)-1]
166		return strings.TrimPrefix(name, remote+"/")
167	}
168	
169	// createWorktreeFromRemote handles the common flow for checking out a remote
170	// branch into a new worktree: check if it already exists, fetch, create, and
171	// optionally run init. Used by both `wt new --from` and `wt pr`.
172	func createWorktreeFromRemote(ctx *cmdContext, name, remoteBranch string, doInit bool) error {
173		wtPath := ctx.worktreePath(name)
174	
175		if isDir(wtPath) {
176			return fmt.Errorf("worktree already exists: %s\n   Use wt switch %s to switch to it", wtPath, name)
177		}
178	
179		// Fetch to get latest refs
180		spin := ui.NewSpinner("Fetching latest refs")
181		if err := git.FetchAll(ctx.Config.Remote); err != nil {
182			spin.Stop()
183			ui.Warn("Fetch failed: %v", err)
184		} else {
185			spin.Stop()
186		}
187	
188		localBranch := strings.TrimPrefix(remoteBranch, ctx.Config.Remote+"/")
189		remoteRef := ctx.Config.Remote + "/" + localBranch
190	
191		fmt.Println("Creating worktree from existing branch...")
192		fmt.Printf("  Directory: %s\n", wtPath)
193		fmt.Printf("  Branch: %s\n", localBranch)
194		fmt.Println()
195	
196		err := git.AddWorktreeFromRemote(wtPath, localBranch, remoteRef)
197		if err != nil {
198			// Branch might already exist locally
199			err = git.AddWorktreeFromExisting(wtPath, localBranch)
200		}
201		if err != nil {
202			return fmt.Errorf("failed to create worktree: %w", err)
203		}
204	
205		fmt.Println()
206		ui.Success("Created worktree")
207		fmt.Println()
208	
209		if doInit {
210			return runInitIn(wtPath, ctx)
211		}
212		printSwitchHint(name)
213		return nil
214	}
215	
216	// printSwitchHint prints the next-step command and offers to copy it to the clipboard.
217	func printSwitchHint(name string) {
218		switchCmd := fmt.Sprintf("wt switch %s && wt init", name)
219		fmt.Printf("  → %s\n", switchCmd)
220		ui.PrintCTA("wt switch "+name, "wt init")
221	
222		if ui.IsTTY() && ui.ClipboardAvailable() {
223			if ui.Confirm("Copy to clipboard?", true) {
224				if err := ui.CopyToClipboard(switchCmd); err != nil {
225					ui.Warn("Failed to copy: %v", err)
226				} else {
227					ui.Success("Copied to clipboard")
228				}
229			}
230		}
231	}
232	
233	func newFromBase(ctx *cmdContext, name string) error {
234		branch := ctx.branchName(name)
235		wtPath := ctx.worktreePath(name)
236	
237		if isDir(wtPath) {
238			return fmt.Errorf("worktree already exists: %s\n   Use wt switch %s to switch to it", wtPath, name)
239		}
240	
241		if git.BranchExists(branch) {
242			return fmt.Errorf("branch already exists: %s\n   Use wt new --from %s to create a worktree for it\n   Or wt switch %s if the worktree already exists", branch, branch, name)
243		}
244	
245		fmt.Println("Creating worktree...")
246		fmt.Printf("  Directory: %s\n", wtPath)
247		fmt.Printf("  Branch: %s (from %s)\n", branch, ctx.Config.BaseBranch)
248		fmt.Println()
249	
250		// Fetch latest base branch
251		spin := ui.NewSpinner(fmt.Sprintf("Fetching %s", ctx.Config.BaseBranch))
252		if err := git.Fetch(ctx.Config.Remote, ctx.Config.BaseBranch); err != nil {
253			spin.Stop()
254			ui.Warn("Fetch failed: %v", err)
255		} else {
256			spin.Stop()
257		}
258	
259		if err := git.AddWorktree(wtPath, branch, ctx.baseRef()); err != nil {
260			return fmt.Errorf("failed to create worktree: %w", err)
261		}
262	
263		fmt.Println()
264		ui.Success("Created worktree")
265		fmt.Println()
266	
267		if newDoInit {
268			return runInitIn(wtPath, ctx)
269		}
270		printSwitchHint(name)
271		return nil
272	}
