1	package git
2	
3	import (
4		"fmt"
5		"strconv"
6		"strings"
7	)
8	
9	// LogEntry is one commit summary used by the dashboard detail panel.
10	type LogEntry struct {
11		Hash    string // short
12		Subject string
13		Age     string // already shortened, e.g. "2h"
14	}
15	
16	// LogOnelineIn returns up to n commits reachable from HEAD but not from base,
17	// most recent first. Returns nil (not error) if the range is empty.
18	func LogOnelineIn(dir, base string, n int) ([]LogEntry, error) {
19		if n <= 0 {
20			return nil, nil
21		}
22		out, err := RunIn(dir, "log",
23			fmt.Sprintf("-%d", n),
24			"--format=%h\t%s\t%cr",
25			base+"..HEAD",
26		)
27		if err != nil {
28			return nil, err
29		}
30		if out == "" {
31			return nil, nil
32		}
33		lines := strings.Split(out, "\n")
34		entries := make([]LogEntry, 0, len(lines))
35		for _, line := range lines {
36			parts := strings.SplitN(line, "\t", 3)
37			if len(parts) < 3 {
38				continue
39			}
40			entries = append(entries, LogEntry{
41				Hash:    parts[0],
42				Subject: parts[1],
43				Age:     shortenAge(parts[2]),
44			})
45		}
46		return entries, nil
47	}
48	
49	// DiffStats summarises a diff between base and HEAD.
50	type DiffStats struct {
51		Commits   int
52		Files     int
53		Additions int
54		Deletions int
55	}
56	
57	// DiffStatsIn returns commits-ahead and shortstat (files/additions/deletions)
58	// for HEAD vs base. Empty range yields zeroed struct, not an error.
59	func DiffStatsIn(dir, base string) (DiffStats, error) {
60		stats := DiffStats{}
61	
62		commitsStr, err := RunIn(dir, "rev-list", "--count", base+"..HEAD")
63		if err != nil {
64			return stats, err
65		}
66		stats.Commits, _ = strconv.Atoi(strings.TrimSpace(commitsStr))
67	
68		if stats.Commits == 0 {
69			return stats, nil
70		}
71	
72		// `git diff --shortstat` output: " 14 files changed, 247 insertions(+), 82 deletions(-)"
73		shortstat, err := RunIn(dir, "diff", "--shortstat", base+"..HEAD")
74		if err != nil {
75			return stats, err
76		}
77		stats.Files, stats.Additions, stats.Deletions = parseShortstat(shortstat)
78		return stats, nil
79	}
80	
81	func parseShortstat(s string) (files, adds, dels int) {
82		for part := range strings.SplitSeq(s, ",") {
83			part = strings.TrimSpace(part)
84			fields := strings.Fields(part)
85			if len(fields) < 2 {
86				continue
87			}
88			n, err := strconv.Atoi(fields[0])
89			if err != nil {
90				continue
91			}
92			switch {
93			case strings.HasPrefix(fields[1], "file"):
94				files = n
95			case strings.HasPrefix(fields[1], "insertion"):
96				adds = n
97			case strings.HasPrefix(fields[1], "deletion"):
98				dels = n
99			}
100		}
101		return
102	}
103	
104	// DiffFile is one entry from `git diff --name-status`.
105	type DiffFile struct {
106		Status string // "M", "A", "D", "R", "C", "T", etc.
107		Path   string
108	}
109	
110	// CommitDetail is the full info shown for one commit in the dashboard's
111	// commit-detail panel.
112	type CommitDetail struct {
113		Hash    string
114		Author  string
115		Email   string
116		Date    string // ISO-8601 from %ai, already formatted
117		Subject string
118		Body    string
119		Files   []CommitFile
120	}
121	
122	// CommitFile is one file changed by a commit, with line counts.
123	// Status is derived from the numstat counts:
124	//
125	//	A (added)    when Dels == 0 && Adds > 0
126	//	D (deleted)  when Adds == 0 && Dels > 0
127	//	M (modified) when both are non-zero
128	//	B (binary)   when numstat reports "-" for either
129	type CommitFile struct {
130		Status string
131		Path   string
132		Adds   int
133		Dels   int
134	}
135	
136	// CommitDetailIn fetches the metadata and per-file change list for a commit.
137	// Two git calls — both fast — combined into a single struct.
138	func CommitDetailIn(dir, hash string) (CommitDetail, error) {
139		var d CommitDetail
140	
141		// Metadata: null-separated to survive any character that might appear in
142		// subject/body (newlines, tabs, unicode, etc.).
143		metaOut, err := RunIn(dir, "show", "-s",
144			"--format=%H%x00%an%x00%ae%x00%ai%x00%s%x00%b", hash)
145		if err != nil {
146			return d, err
147		}
148		parts := strings.SplitN(metaOut, "\x00", 6)
149		if len(parts) < 6 {
150			return d, fmt.Errorf("unexpected git show output for %s", hash)
151		}
152		d.Hash = parts[0]
153		d.Author = parts[1]
154		d.Email = parts[2]
155		d.Date = parts[3]
156		d.Subject = parts[4]
157		d.Body = strings.TrimSpace(parts[5])
158	
159		// Per-file changes via numstat.
160		numOut, err := RunIn(dir, "show", "--numstat", "--format=", hash)
161		if err != nil {
162			// Metadata is still useful; return what we have.
163			return d, nil
164		}
165		for line := range strings.SplitSeq(numOut, "\n") {
166			fields := strings.Fields(line)
167			if len(fields) < 3 {
168				continue
169			}
170			addsStr, delsStr := fields[0], fields[1]
171			path := fields[len(fields)-1]
172	
173			f := CommitFile{Path: path}
174			switch {
175			case addsStr == "-" || delsStr == "-":
176				f.Status = "B"
177			default:
178				f.Adds, _ = strconv.Atoi(addsStr)
179				f.Dels, _ = strconv.Atoi(delsStr)
180				switch {
181				case f.Adds > 0 && f.Dels == 0:
182					f.Status = "A"
183				case f.Adds == 0 && f.Dels > 0:
184					f.Status = "D"
185				default:
186					f.Status = "M"
187				}
188			}
189			d.Files = append(d.Files, f)
190		}
191	
192		return d, nil
193	}
194	
195	// DiffFilesIn returns per-file change status between base and HEAD.
196	func DiffFilesIn(dir, base string) ([]DiffFile, error) {
197		out, err := RunIn(dir, "diff", "--name-status", base+"..HEAD")
198		if err != nil {
199			return nil, err
200		}
201		if out == "" {
202			return nil, nil
203		}
204		lines := strings.Split(out, "\n")
205		changes := make([]DiffFile, 0, len(lines))
206		for _, line := range lines {
207			fields := strings.Fields(line)
208			if len(fields) < 2 {
209				continue
210			}
211			// Rename/copy entries have an extra "score" suffix on the status (e.g. "R100")
212			// and a second path; we only surface the first letter and the destination path.
213			status := string(fields[0][0])
214			path := fields[len(fields)-1]
215			changes = append(changes, DiffFile{Status: status, Path: path})
216		}
217		return changes, nil
218	}
